+        // Packages should be sorted by BTreeSet order
+        let names: Vec<_> = graph
+            .packages
+            .iter()
+            .map(|p| p.package_name.as_str())
+            .collect();
+        assert_eq!(names, vec!["a", "b", "c", "d"]);
+    }
